from flask import Flask, request
from prometheus_client import Counter, Gauge, Histogram, prometheus_client

app = Flask(__name__)

# Request counters
requests_total = Counter('app_requests_total', 'Total number of requests')
failed_requests = Counter('app_failed_requests_total', 'Total number of failed requests')

# Latency gauges
request_latency = Gauge('app_request_latency_seconds', 'Request latency in seconds')

# Business metrics histograms
transactions_amount = Histogram('app_transactions_amount_usd', 'Total amount of transactions in USD')

@app.route('/')
def index():
    requests_total.inc()
    request_latency.set(request.duration_seconds)
    transactions_amount.observe(100)
    return 'Hello, World!'

@app.route('/metrics')
def metrics():
    return prometheus_client.generate_latest()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)